import './TimelineHorizontal.scss';

import type { FC } from 'react';
import React, { useMemo } from 'react';

import { classNames } from '../../../helpers/classnames';
import { Typography } from '../../Typography';
import type { AtomPosition, StageType, TimelineIconType } from '../Timeline.types';
import { TimelineAtom } from '../TimelineAtom';
import { calcAtomType, calcStepPosition } from '../utils';
import type { TimelineHorizontalProps } from './TimelineHorizontal.types';

export const TimelineHorizontal: FC<TimelineHorizontalProps> = ({ steps, activeStepIndex = -1, completed }) => {
	const stepsLength = steps.length;

	/** Находим активный шаг по его индексу. */
	const activeStep: StageType | undefined = useMemo(
		() => (completed ? steps.at(-1) : steps[activeStepIndex]),
		[activeStepIndex, completed, steps],
	);

	/** Количество пройденных шагов. */
	const completedStepsCount = useMemo((): number => {
		if (completed) {
			return stepsLength;
		}

		if (activeStepIndex < 0) {
			return 0;
		}

		return activeStepIndex;
	}, [completed, activeStepIndex, stepsLength]);

	return (
		<li data-testid="TimelineHorizontal" className="dsb_timeline__horizontal" role="listitem">
			{activeStep && (
				<div className="dsb_timeline-body">
					<div className="dsb_timeline-body-title">
						<Typography variant="overline" className="dsb_timeline-body-title-name">
							Текущий этап
						</Typography>
						<div className="dsb_timeline-body-title-stages">
							<Typography variant="subtitle1" className="dsb_timeline-body-stages-number">
								{activeStep.title}
							</Typography>
						</div>
					</div>
					{activeStep?.action}
				</div>
			)}

			<div className="dsb_timeline-atom">
				{steps.map((step, index) => {
					const { id, error = false } = step;
					const position: AtomPosition = calcStepPosition(index, stepsLength - 1);

					const type: TimelineIconType = completed ? 'active' : calcAtomType(index, activeStepIndex, error);

					return <TimelineAtom key={id} type={type} position={position} direction="horizontal" />;
				})}
			</div>

			<div className="dsb_timeline-bottom">
				<Typography
					variant="body2"
					className={classNames('dsb_timeline-bottom-text', activeStep?.error && 'dsb_timeline-bottom-text__error')}
				>
					{activeStep?.text}
				</Typography>

				<Typography variant="body2" className="dsb_timeline-bottom-count-page">
					{`Завершено ${completedStepsCount} из ${stepsLength} этапов`}
				</Typography>
			</div>
		</li>
	);
};
